579	  private shouldPauseReconnectAfterAuthFailure(detailCode: string | null): boolean {
580	    if (!detailCode) {
581	      return false;
582	    }
583	    if (
584	      detailCode === ConnectErrorDetailCodes.AUTH_TOKEN_MISSING ||
585	      detailCode === ConnectErrorDetailCodes.AUTH_BOOTSTRAP_TOKEN_INVALID ||
586	      detailCode === ConnectErrorDetailCodes.AUTH_PASSWORD_MISSING ||
587	      detailCode === ConnectErrorDetailCodes.AUTH_PASSWORD_MISMATCH ||
588	      detailCode === ConnectErrorDetailCodes.AUTH_RATE_LIMITED ||
589	      detailCode === ConnectErrorDetailCodes.PAIRING_REQUIRED ||
590	      detailCode === ConnectErrorDetailCodes.CONTROL_UI_DEVICE_IDENTITY_REQUIRED ||
591	      detailCode === ConnectErrorDetailCodes.DEVICE_IDENTITY_REQUIRED
592	    ) {
593	      return true;
594	    }
595	    if (detailCode !== ConnectErrorDetailCodes.AUTH_TOKEN_MISMATCH) {
596	      return false;
597	    }
598	    if (this.pendingDeviceTokenRetry) {
599	      return false;
600	    }
601	    // If the endpoint is not trusted for retry, mismatch is terminal until operator action.
602	    if (!this.isTrustedDeviceRetryEndpoint()) {
603	      return true;
604	    }
605	    // Pause mismatch reconnect loops once the one-shot device-token retry is consumed.
606	    return this.deviceTokenRetryBudgetUsed;
607	  }
