609	  private shouldRetryWithStoredDeviceToken(params: {
610	    error: unknown;
611	    explicitGatewayToken?: string;
612	    storedToken?: string;
613	    resolvedDeviceToken?: string;
614	  }): boolean {
615	    if (this.deviceTokenRetryBudgetUsed) {
616	      return false;
617	    }
618	    if (params.resolvedDeviceToken) {
619	      return false;
620	    }
621	    if (!params.explicitGatewayToken || !params.storedToken) {
622	      return false;
623	    }
624	    if (!this.isTrustedDeviceRetryEndpoint()) {
625	      return false;
626	    }
627	    if (!(params.error instanceof GatewayClientRequestError)) {
628	      return false;
629	    }
630	    const detailCode = readConnectErrorDetailCode(params.error.details);
631	    const advice: ConnectErrorRecoveryAdvice = readConnectErrorRecoveryAdvice(params.error.details);
632	    const retryWithDeviceTokenRecommended =
633	      advice.recommendedNextStep === "retry_with_device_token";
634	    return (
635	      advice.canRetryWithDeviceToken === true ||
636	      retryWithDeviceTokenRecommended ||
637	      detailCode === ConnectErrorDetailCodes.AUTH_TOKEN_MISMATCH
638	    );
639	  }
