641	  private isTrustedDeviceRetryEndpoint(): boolean {
642	    const rawUrl = this.opts.url ?? "ws://127.0.0.1:18789";
643	    try {
644	      const parsed = new URL(rawUrl);
645	      const protocol =
646	        parsed.protocol === "https:"
647	          ? "wss:"
648	          : parsed.protocol === "http:"
649	            ? "ws:"
650	            : parsed.protocol;
651	      if (isLoopbackHost(parsed.hostname)) {
652	        return true;
653	      }
654	      return protocol === "wss:" && Boolean(this.opts.tlsFingerprint?.trim());
655	    } catch {
656	      return false;
657	    }
658	  }
