660	  private selectConnectAuth(role: string): SelectedConnectAuth {
661	    const explicitGatewayToken = this.opts.token?.trim() || undefined;
662	    const explicitBootstrapToken = this.opts.bootstrapToken?.trim() || undefined;
663	    const explicitDeviceToken = this.opts.deviceToken?.trim() || undefined;
664	    const authPassword = this.opts.password?.trim() || undefined;
665	    const storedAuth = this.loadStoredDeviceAuth(role);
666	    const storedToken = storedAuth?.token ?? null;
667	    const storedScopes = storedAuth?.scopes;
668	    const shouldUseDeviceRetryToken =
669	      this.pendingDeviceTokenRetry &&
670	      !explicitDeviceToken &&
671	      Boolean(explicitGatewayToken) &&
672	      Boolean(storedToken) &&
673	      this.isTrustedDeviceRetryEndpoint();
674	    const resolvedDeviceToken =
675	      explicitDeviceToken ??
676	      (shouldUseDeviceRetryToken ||
677	      (!(explicitGatewayToken || authPassword) && (!explicitBootstrapToken || Boolean(storedToken)))
678	        ? (storedToken ?? undefined)
679	        : undefined);
680	    const reusingStoredDeviceToken =
681	      Boolean(resolvedDeviceToken) &&
682	      !explicitDeviceToken &&
683	      Boolean(storedToken) &&
684	      resolvedDeviceToken === storedToken;
685	    // Legacy compatibility: keep `auth.token` populated for device-token auth when
686	    // no explicit shared token is present.
687	    const authToken = explicitGatewayToken ?? resolvedDeviceToken;
688	    const authBootstrapToken =
689	      !explicitGatewayToken && !resolvedDeviceToken ? explicitBootstrapToken : undefined;
690	    return {
691	      authToken,
692	      authBootstrapToken,
693	      authDeviceToken: shouldUseDeviceRetryToken ? (storedToken ?? undefined) : undefined,
694	      authPassword,
695	      signatureToken: authToken ?? authBootstrapToken ?? undefined,
696	      resolvedDeviceToken,
697	      storedToken: storedToken ?? undefined,
698	      storedScopes,
699	      usingStoredDeviceToken: reusingStoredDeviceToken,
700	    };
701	  }
