703	  private handleMessage(raw: string) {
704	    try {
705	      const parsed = JSON.parse(raw);
706	      if (validateEventFrame(parsed)) {
707	        this.lastTick = Date.now();
708	        const evt = parsed;
709	        if (evt.event === "connect.challenge") {
710	          const payload = evt.payload as { nonce?: unknown } | undefined;
711	          const nonce = payload && typeof payload.nonce === "string" ? payload.nonce : null;
712	          if (!nonce || nonce.trim().length === 0) {
713	            this.opts.onConnectError?.(new Error("gateway connect challenge missing nonce"));
714	            this.ws?.close(1008, "connect challenge missing nonce");
715	            return;
716	          }
717	          this.connectNonce = nonce.trim();
718	          this.sendConnect();
719	          return;
720	        }
721	        const seq = typeof evt.seq === "number" ? evt.seq : null;
722	        if (seq !== null) {
723	          if (this.lastSeq !== null && seq > this.lastSeq + 1) {
724	            this.opts.onGap?.({ expected: this.lastSeq + 1, received: seq });
725	          }
726	          this.lastSeq = seq;
727	        }
728	        if (evt.event === "tick") {
729	          this.lastTick = Date.now();
730	        }
731	        this.opts.onEvent?.(evt);
732	        return;
733	      }
734	      if (validateResponseFrame(parsed)) {
735	        this.lastTick = Date.now();
736	        const pending = this.pending.get(parsed.id);
737	        if (!pending) {
738	          return;
739	        }
740	        // If the payload is an ack with status accepted, keep waiting for final.
741	        const payload = parsed.payload as { status?: unknown } | undefined;
742	        const status = payload?.status;
743	        if (pending.expectFinal && status === "accepted") {
744	          return;
745	        }
746	        this.pending.delete(parsed.id);
747	        if (pending.timeout) {
748	          clearTimeout(pending.timeout);
749	        }
750	        if (parsed.ok) {
751	          pending.resolve(parsed.payload);
752	        } else {
753	          pending.reject(
754	            new GatewayClientRequestError({
755	              code: parsed.error?.code,
756	              message: parsed.error?.message ?? "unknown error",
757	              details: parsed.error?.details,
758	            }),
759	          );
760	        }
761	      }
762	    } catch (err) {
763	      logDebug(`gateway client parse error: ${String(err)}`);
764	    }
765	  }
