780	  private armConnectChallengeTimeout() {
781	    const connectChallengeTimeoutMs = resolveGatewayClientConnectChallengeTimeoutMs(this.opts);
782	    const armedAt = Date.now();
783	    this.clearConnectChallengeTimeout();
784	    this.connectTimer = setTimeout(() => {
785	      if (this.connectSent || this.ws?.readyState !== WebSocket.OPEN) {
786	        return;
787	      }
788	      const elapsedMs = Date.now() - armedAt;
789	      this.opts.onConnectError?.(
790	        new Error(
791	          `gateway connect challenge timeout (waited ${elapsedMs}ms, limit ${connectChallengeTimeoutMs}ms)`,
792	        ),
