798	  private scheduleReconnect() {
799	    if (this.closed) {
800	      return;
801	    }
802	    if (this.tickTimer) {
803	      clearInterval(this.tickTimer);
804	      this.tickTimer = null;
805	    }
806	    const delay = this.backoffMs;
807	    this.backoffMs = Math.min(this.backoffMs * 2, 30_000);
808	    setTimeout(() => this.start(), delay).unref();
809	  }
