811	  private flushPendingErrors(err: Error) {
812	    for (const [, p] of this.pending) {
813	      if (p.timeout) {
814	        clearTimeout(p.timeout);
815	      }
816	      p.reject(err);
817	    }
818	    this.pending.clear();
819	  }
