821	  private startTickWatch() {
822	    if (this.tickTimer) {
823	      clearInterval(this.tickTimer);
824	    }
825	    const rawMinInterval = this.opts.tickWatchMinIntervalMs;
826	    const minInterval =
827	      typeof rawMinInterval === "number" && Number.isFinite(rawMinInterval)
828	        ? Math.max(1, Math.min(30_000, rawMinInterval))
829	        : 1000;
830	    const interval = Math.max(this.tickIntervalMs, minInterval);
831	    this.tickTimer = setInterval(() => {
832	      if (this.closed) {
833	        return;
834	      }
835	      if (!this.lastTick) {
836	        return;
837	      }
838	      const gap = Date.now() - this.lastTick;
839	      if (gap > this.tickIntervalMs * 2) {
840	        this.ws?.close(4000, "tick timeout");
841	      }
842	    }, interval);
843	  }
