845	  private validateTlsFingerprint(): Error | null {
846	    if (!this.opts.tlsFingerprint || !this.ws) {
847	      return null;
848	    }
849	    const expected = normalizeFingerprint(this.opts.tlsFingerprint);
850	    if (!expected) {
851	      return new Error("gateway tls fingerprint missing");
852	    }
853	    const socket = (
854	      this.ws as WebSocket & {
855	        _socket?: { getPeerCertificate?: () => { fingerprint256?: string } };
856	      }
857	    )._socket;
858	    if (!socket || typeof socket.getPeerCertificate !== "function") {
859	      return new Error("gateway tls fingerprint unavailable");
860	    }
861	    const cert = socket.getPeerCertificate();
862	    const fingerprint = normalizeFingerprint(cert?.fingerprint256 ?? "");
863	    if (!fingerprint) {
864	      return new Error("gateway tls fingerprint unavailable");
865	    }
866	    if (fingerprint !== expected) {
867	      return new Error("gateway tls fingerprint mismatch");
868	    }
869	    return null;
870	  }
