872	  async request<T = Record<string, unknown>>(
873	    method: string,
874	    params?: unknown,
875	    opts?: { expectFinal?: boolean; timeoutMs?: number | null },
876	  ): Promise<T> {
877	    if (!this.ws || this.ws.readyState !== WebSocket.OPEN) {
878	      throw new Error("gateway not connected");
879	    }
880	    const id = randomUUID();
881	    const frame: RequestFrame = { type: "req", id, method, params };
882	    if (!validateRequestFrame(frame)) {
883	      throw new Error(
884	        `invalid request frame: ${JSON.stringify(validateRequestFrame.errors, null, 2)}`,
885	      );
886	    }
887	    const expectFinal = opts?.expectFinal === true;
888	    const timeoutMs =
889	      opts?.timeoutMs === null
890	        ? null
891	        : typeof opts?.timeoutMs === "number" && Number.isFinite(opts.timeoutMs)
892	          ? Math.max(1, Math.min(Math.floor(opts.timeoutMs), 2_147_483_647))
893	          : expectFinal
894	            ? null
895	            : this.requestTimeoutMs;
896	    const p = new Promise<T>((resolve, reject) => {
897	      const timeout =
898	        timeoutMs === null
899	          ? null
900	          : setTimeout(() => {
901	              this.pending.delete(id);
902	              reject(new Error(`gateway request timeout for ${method}`));
903	            }, timeoutMs);
904	      this.pending.set(id, {
905	        resolve: (value) => resolve(value as T),
906	        reject,
907	        expectFinal,
908	        timeout,
909	      });
910	    });
911	    this.ws.send(JSON.stringify(frame));
912	    return p;
913	  }
914	}
